import React, { useState } from 'react';
import axios from 'axios';

const BookingForm = () => {
  const [formData, setFormData] = useState({ name: '', email: '', date: '', zone: '' });

  const handleChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post('http://localhost:8080/bookings', formData);
      alert('Booking submitted! Proceed to payment.');
      // Razorpay integration
      const options = {
        key: 'YOUR_RAZORPAY_KEY', // Get from Razorpay dashboard
        amount: 50000, // e.g., 500 INR * 100
        currency: 'INR',
        name: 'Ranthambhore Safari',
        description: 'Safari Booking',
        handler: function (response) {
          alert('Payment successful: ' + response.razorpay_payment_id);
          // Update booking status in backend if needed
        },
      };
      const rzp = new window.Razorpay(options);
      rzp.open();
    } catch (error) {
      alert('Error submitting booking');
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <input name="name" placeholder="Name" onChange={handleChange} className="border p-2 w-full" required />
      <input name="email" type="email" placeholder="Email" onChange={handleChange} className="border p-2 w-full" required />
      <input name="date" type="date" onChange={handleChange} className="border p-2 w-full" required />
      <select name="zone" onChange={handleChange} className="border p-2 w-full" required>
        <option value="">Select Zone</option>
        <option value="Zone 1">Zone 1</option>
        {/* Add more zones */}
      </select>
      <button type="submit" className="bg-blue-500 text-white p-2">Book Now</button>
    </form>
  );
};

export default BookingForm;
